const Q_FINE_ART_2010=[{"id": "objective>Fine Art>2010>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Artworks that are produced to serve a utilitarian purpose are classified as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">applied arts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fine arts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberal arts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">theatre arts.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is art that is more utilitarian and has a function but retains an artistic style and still requires talent to create. The decorative arts include ceramics, furniture making, textiles, interior design, jewelry making, metal crafting, and woodworking.</div>", "topic": "CLASSIFICATION OF ART"}, {"id": "objective>Fine Art>2010>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Literary art involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">painting and sculpture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">architecture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drama</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poetry and prose.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Literary art refers to the written work that has artistic or intellectual value. This includes genres such as poetry and prose. Poetry is a form of literary art that uses aesthetic and rhythmic qualities of language to evoke meanings in addition to, or in place of, the prosaic ostensible meaning. Prose is a form of language that has no formal metrical structure. It applies a natural flow of speech, and ordinary grammatical structure rather than rhythmic structure, such as in the case of traditional poetry.</div>", "topic": "ART TERMS"}, {"id": "objective>Fine Art>2010>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> If the shape illustrated above is a mould, which of the following will best fit into it?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAEUAAAAhCAAAAACqgzm5AAAAB3RJTUUH4goKFCAteSGblwAAAIZJREFUSInllc0KwCAMg9e9/zt3h4EOTGyUIpT1oD3oZ1L/zK+EuDMg/6NYBkWEhI40zoG6qIbK7LS1Jgpjt/EzO76wiIKWn5OgFuhixsGORsyGloETVSanuidOnfooM4q9EG/5thaX1RCKNYCE4Vq896ElSnGQ0SBnd/HHXB2Po8pbV5PyAIK7GzDDM+t7AAAAAElFTkSuQmCC\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In fine arts, shapes are two-dimensional forms that define the outline of objects. They are categorized into geometric shapes (e.g., squares, circles) and organic shapes (e.g., leaves, clouds). Shapes contribute to composition, symbolism, and visual interest, influencing how viewers perceive and interpret artworks.</div>", "topic": "ELEMENTS AND PRINCIPLES OF DESIGN"}, {"id": "objective>Fine Art>2010>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">basic shapes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">basic forms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elliptical shapes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elliptical forms</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In fine arts, shapes are two-dimensional forms that define the outline of objects. They are categorized into geometric shapes (e.g., squares, circles) and organic shapes (e.g., leaves, clouds). Shapes contribute to composition, symbolism, and visual interest, influencing how viewers perceive and interpret artworks.</div>", "topic": "ELEMENTS AND PRINCIPLES OF DESIGN"}, {"id": "objective>Fine Art>2010>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Emphasis in a composition, means that attention is drawn to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">certain parts than others</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colours predominantly used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the entire surface of the composition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colour harmony.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Emphasis in a composition means that certain parts of the artwork are given more importance or prominence than others. This can be achieved through various means, such as size, color, texture, shape, position, etc. The parts of the artwork that are emphasized draw the viewer's attention first and are often the focal point of the piece.</div>", "topic": "ELEMENTS AND PRINCIPLES OF DESIGN"}, {"id": "objective>Fine Art>2010>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The illustration reflects contrasts of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shape and size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">size and texture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tone and shape</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tone and size.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Contrast in art refers to the difference between elements, such as color, texture, shape, or light and shadow, that enhances visual interest and emphasizes specific features. It creates a dynamic relationship within the composition, guiding the viewer's attention and evoking emotional responses, ultimately enriching the overall artistic expression.</div>", "topic": "ELEMENTS AND PRINCIPLES OF DESIGN"}, {"id": "objective>Fine Art>2010>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The effect of solidity is best exhibited in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of solidity in art refers to the perception of three-dimensionality and weight in two-dimensional works. This effect is achieved through techniques like shading, perspective, and texture, creating a realistic sense of form. It enhances the viewer's experience by making subjects appear grounded, tangible, and more lifelike.</div>", "topic": "ELEMENTS AND PRINCIPLES OF DESIGN"}, {"id": "objective>Fine Art>2010>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect produced by the combination of light, shape and colour is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shading</div>", "<div style=\"font-family:Cambria;font-size:17px;\">painting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chiaroscuro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">serigraphy.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chiaroscuro is a technique that uses strong contrasts between light and dark to create the illusion of volume in modeling three-dimensional objects and figures. This technique effectively combines light, shape, and color to produce depth and emphasis in artwork.</div>", "topic": "ART TERMS"}, {"id": "objective>Fine Art>2010>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A permanent pattern made on the skin is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">body design</div>", "<div style=\"font-family:Cambria;font-size:17px;\">body painting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graffito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tatoo.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A permanent pattern made on the skin is called a tattoo. Tattoos are a form of body modification where a design is made by inserting ink, dyes, and/or pigments, either indelible or temporary, into the dermis layer of the skin to change the pigment.</div>", "topic": "ART TERMS"}, {"id": "objective>Fine Art>2010>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plasticine is an art medium that can be used in place of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ivory</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Plasticine is an art medium that can be used in place of clay. Plasticine is a type of modelling clay that is non-toxic, soft, and never hardens, making it a good material for modelling. It can be easily worked by hand or with tools, and its non-drying property makes it a good substitute for clay in certain art projects.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mosaic art of decoration was introduced during the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Romanesque period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gothic period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Medieval Period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prehistoric period.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mosaic art was introduced during the Romanesque period. Mosaic is a technique of decorative art or interior decoration. Most mosaics are made of small, flat, roughly square, pieces of stone or glass of different colors, known as tesserae.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An abstract art is a realistic representation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drawing of human figures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">still life drawings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distorted representation of an artwork.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Abstract art does not aim to represent external reality accurately. Instead, it often distorts or simplifies forms, colors, and shapes to convey emotions or ideas, moving away from realistic representations found in nature, human figures, or still life.</div>", "topic": "ART TERMS"}, {"id": "objective>Fine Art>2010>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following does a textile artist use to form patterns?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Logo.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motif</div>", "<div style=\"font-family:Cambria;font-size:17px;\">posters</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A textile artist uses motifs to form patterns. A motif is a decorative design or pattern. In textile art, it is a principal recurring theme or element in a work.</div>", "topic": "ARTISTIC SKILLS, TECHNIQUES AND PROCESSES"}, {"id": "objective>Fine Art>2010>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Varnish is essential for the protection of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oil painting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water colour painting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pastel painting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gouache painting.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Varnish is a clear transparent hard protective finish or film used in wood finishing and in art. Varnish is traditionally a combination of a drying oil, a resin, and a thinner or solvent. It is particularly used in oil painting to protect the paint from dust, dirt and other environmental factors that could damage the artwork. Therefore, varnish is essential for the protection of oil painting.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Byzantine art emerged in the 4th century in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Constantinople</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rome</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paris</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Crete</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Byzantine art refers to the body of Christian Greek artistic products of the Eastern Roman (Byzantine) Empire, as well as the nations and states that inherited culturally from the empire. It emerged in the 4th century in Constantinople (modern-day Istanbul), which was the capital of the Byzantine Empire.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Pointillism became more popular during</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Classicism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Modern Art</div>", "<div style=\"font-family:Cambria;font-size:17px;\">impressionism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Renaissance.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pointillism is a technique of painting in which small, distinct dots of color are applied in patterns to form an image. Georges Seurat and Paul Signac developed the technique in 1886, branching from Impressionism. Therefore, Pointillism became more popular during the Impressionism period.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following supports was used by Roman painters for expression?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Canvas.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Walls.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wooden panels.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Metal panels.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Roman painters often used walls as their canvas, especially for frescoes. Frescoes are a type of mural painting where the paint is applied directly onto wet plaster, allowing the paint to become an integral part of the wall as it dries. This technique was commonly used in Roman times.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The glory of the Gothic Cathedrals is in their</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">complex architectural rendering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">simple architectural rendering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of magnificent stained glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of colourful marbles.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The glory of the Gothic Cathedrals is in their use of magnificent stained glass. Gothic architecture is known for its grand, tall designs and intricate detail work. One of the most notable features of Gothic cathedrals is the extensive use of stained glass, which was used to create beautiful, colorful windows that told stories from the Bible or depicted saints.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prehistoric cave paintings reflected</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buildings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">people</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prehistoric cave paintings primarily reflected animals. These paintings, often found in caves, depicted various types of animals, including horses, bison, and deer. The focus on animals suggests that these paintings may have been used for ritualistic or symbolic purposes, perhaps related to hunting.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Egyptian sculptural piece that is half man and half animal is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sphinx</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mummy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mastaba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nefetiti</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sphinx is a mythical creature with the body of a lion and the head of a human, often built by the ancient Egyptians for their pharaohs. The other options do not represent a half man and half animal sculptural piece.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dogon of Mali is renown for its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">masks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">textiles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">engravings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decorations.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Dogon people of Mali are known for their mask ceremonies and their wooden sculptures, not for textiles, engravings or decorations.</div>", "topic": "TRADITIONAL AFRICAN ART"}, {"id": "objective>Fine Art>2010>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are characteristics of Egyptian arts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Roundness of shoulder.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Short feet and small thighs.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rigidity and frontality.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Use of bright and raw colours.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Egyptian art is known for its rigidity and frontality. The figures are often depicted in a strict frontal view and their bodies are rigid, showing little movement. The other options do not accurately describe characteristics of Egyptian art.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Mbari artists were mainly based in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lagos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oshogbo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibadan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Esie.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is Ibadan. <br/> The Mbari artists were part of the Mbari Club, an artistic and cultural movement founded in Ibadan, Nigeria in the early 1960s. The club was a hub for artists, writers, and intellectuals, promoting modern African art and literature.</div>", "topic": "DEVELOPMENT IN CONTEMPORARY NIGERIAN ARTS AND ARTISTS"}, {"id": "objective>Fine Art>2010>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following towns is famous for the production of calabash?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nok.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oyo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is Oyo. <br/>  <br/> Oyo is renowned for its calabash carving and decoration. The town has a long tradition of creating intricate designs on calabashes, which are used for both functional and decorative purposes.</div>", "topic": "NIGERIAN CRAFTS"}, {"id": "objective>Fine Art>2010>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In traditional Nigerian art, there is a cultural and artistic connection between</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nok and Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nok and Ife</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ife and Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benin and Igala.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is Ife and Benin. <br/> Ife and Benin share a significant cultural and artistic connection. The art of Benin is believed to have been influenced by the earlier Ife civilization, especially in the creation of bronze and terracotta sculptures. Ife is known for its naturalistic human figures, which had an impact on Benin's artistic traditions.</div>", "topic": "TRADITIONAL NIGERIAN ART"}, {"id": "objective>Fine Art>2010>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, thorn carving is practised in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Owo and Shagamu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Owo and Ado - Ekiti</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ado-Ekiti and Ilesha</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shagamu and Oshogbo.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is  Owo and Shagamu. <br/>  <br/> Thorn carving is a traditional craft practiced in Owo and Shagamu in Nigeria. These towns are known for their skilled woodcarvers who create intricate designs and figures using wood, including thorny branches.</div>", "topic": "NIGERIAN CRAFTS"}, {"id": "objective>Fine Art>2010>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The starch used for designing in adire - eleko is boiled with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indigo dye and white alum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow dye and white alum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">green dye and white alum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">red dye and white alum.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adire-eleko is a traditional Nigerian resist-dyed cloth that uses a starch paste to create designs. The starch used for designing in adire-eleko is boiled with indigo dye and white alum. Indigo dye gives the cloth its distinctive blue color, while white alum acts as a mordant, helping the dye adhere to the fabric.</div>", "topic": "NIGERIAN CRAFTS"}, {"id": "objective>Fine Art>2010>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Wood carving in Yorubaland was primarily meant for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">religious purpose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic purpose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">royalty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ceremony.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wood carving in Yorubaland was primarily meant for religious purposes. The Yoruba people have a rich tradition of wood carving, which they used to create intricate sculptures and masks for use in religious ceremonies and rituals. These carvings often depict deities, ancestors, and mythological creatures, and are used to facilitate communication with the spiritual world.</div>", "topic": "TRADITIONAL NIGERIAN ART"}, {"id": "objective>Fine Art>2010>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Zaria Art School is known for its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">natural synthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unnatural synthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motif design</div>", "<div style=\"font-family:Cambria;font-size:17px;\">freedom of expression.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct answer is natural synthesis. <br/>  <br/> The Zaria Art School is known for its concept of \"natural synthesis,\" which blends traditional Nigerian art forms with contemporary, modern art techniques. This approach aimed to harmonize indigenous cultural heritage with Western art education, creating a unique and innovative style.</div>", "topic": "DEVELOPMENT IN CONTEMPORARY NIGERIAN ARTS AND ARTISTS"}, {"id": "objective>Fine Art>2010>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The famous artist who worked with Suzanne Wenger was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Twin Seven Seven</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jimoh Buraimoh</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jimoh Akolo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ulli Beier.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The famous artist who worked with Suzanne Wenger was Twin Seven Seven. Suzanne Wenger was an Austrian artist who moved to Nigeria and became deeply involved in the Yoruba culture. She worked closely with several local artists, including Twin Seven Seven, who was a renowned painter and musician.</div>", "topic": "DEVELOPMENT IN CONTEMPORARY NIGERIAN ARTS AND ARTISTS"}, {"id": "objective>Fine Art>2010>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is regarded as the founder of Nigerian museums?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ben Enwonwu.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jimoh Akolo.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kenneth Murray.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">William Faggs.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kenneth Murray is regarded as the founder of Nigerian museums. He was a British education officer who was posted to Nigeria in the 1920s. He encouraged his students to collect local artifacts, which eventually led to the establishment of the first museum in Nigeria.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first tertiary institution in Nigeria to have an art curriculum was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Yaba College of Technology, Lagos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Institute of Management Technology, Enugu</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Ahmadu Bello University, Zaria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">University of Nigeria, Nsukka.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first tertiary institution in Nigeria to have an art curriculum was Yaba College of Technology, Lagos. The art curriculum was established in 1948.</div>", "topic": "HISTORICAL DIMENSIONS OF ART"}, {"id": "objective>Fine Art>2010>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The annual Igue Festival is celebrated in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Benin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Warri</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ondo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Akure.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The annual Igue Festival is celebrated in Benin City, which is the capital of Edo State in Nigeria. This festival is a significant cultural event that showcases the rich traditions and heritage of the Edo people. The other options, Warri, Ondo, and Akure, are not known for the Igue Festival.</div>", "topic": "TRADITIONAL NIGERIAN ART"}, {"id": "objective>Fine Art>2010>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The use of lines to describe an object is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drawing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graphics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">painting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pottery.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The use of lines to describe an object is known as drawing. Drawing is a form of visual art in which a person uses various drawing instruments to mark paper or another two-dimensional medium. Instruments include graphite pencils, pen and ink, inked brushes, wax color pencils, crayons, charcoal, chalk, pastels, various kinds of erasers, markers, styluses, and various metals.</div>", "topic": "ARTISTIC SKILLS, TECHNIQUES AND PROCESSES"}, {"id": "objective>Fine Art>2010>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dyes are colourants most suitable for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">painting on walls</div>", "<div style=\"font-family:Cambria;font-size:17px;\">printing on papers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drawing on canvas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">printing on fabrics.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dyes are substances that add color to textiles. They are incorporated into the fiber by chemical reaction, absorption, or dispersion. Dyes differ from pigments, which are finely ground solids dispersed in a liquid, such as paint or ink, or used to color materials like plastic. Therefore, dyes are most suitable for printing on fabrics.</div>", "topic": "ART TERMS"}, {"id": "objective>Fine Art>2010>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In lettering, one of the principles is that round characters are placed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">apart</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at an angle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">closely</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overhead</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In lettering, one of the principles is that round characters are placed closely. This is because round characters tend to occupy more space than straight characters, and placing them closely helps to maintain the balance and uniformity of the text.</div>", "topic": "ELEMENTS AND PRINCIPLES OF DESIGN"}, {"id": "objective>Fine Art>2010>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the pictorial composition above, the eye level is represented by line</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">E F</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">K L.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a pictorial composition, the eye level (also called the horizon line) represents the viewer's vantage point. It is an imaginary horizontal line where the sky meets the ground, serving as a reference for perspective. Objects above it appear lower, and those below it appear higher relative to the viewer.</div>", "topic": "ELEMENTS AND PRINCIPLES OF DESIGN"}, {"id": "objective>Fine Art>2010>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An armature is essential to the artists in executing large works in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sculpture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ceramics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carving</div>", "<div style=\"font-family:Cambria;font-size:17px;\">craft.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An armature is a framework around which the sculpture is built. This underlying structure is used to support the material being used to create the outer visible layer of the sculpture. Therefore, an armature is essential to the artists in executing large works in sculpture.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In computer graphics the name given to a device used in navigating the window environment is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">keyboard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ruling pen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mouse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pencil.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In computer graphics, a mouse is a device used for navigating the window environment. It allows the user to move the cursor and select items on the screen.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In corel draw application, ruler guide is used to get the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">top size of a given object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inaccurate size of a given object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower size of a given object</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accurate size of a given object.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Corel Draw application, ruler guides are used to get the accurate size of a given object. They provide a visual aid to positioning objects precisely.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following grades of pencils is good for making dark marks?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2H</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4H</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In pencil grading, the 'B' stands for 'blackness' and the 'H' stands for 'hardness'. A higher B value means the pencil is darker. Therefore, a 4B pencil is good for making dark marks.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is best arranged in order of softness?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3B, 2B, H and HB</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3B, HB, H and 2B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H, HB, 2B and 3B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">, 2B, H and 3B</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hardness or softness of a pencil is indicated by the H or B symbol. H stands for hardness, and B stands for blackness. The higher the number in front of the H, the harder the pencil is, and the lighter the mark will be. The higher the number in front of the B, the softer the pencil is, and the darker the mark will be. Therefore, the correct order from softest to hardest is 3B, 2B, HB, H.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calligraphy pen can be preserved after use by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oiling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">steaming in hot water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rinsing in cold water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greasing.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After using a calligraphy pen, it should be rinsed in cold water to remove any remaining ink. This prevents the ink from drying and clogging the pen, which can affect its performance. Oiling, steaming in hot water, or greasing the pen may damage it.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An atomizer is most ideal in the application of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">linseed oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poster colours.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An atomizer is a device that sprays a substance in a fine mist. It is most commonly used in art to apply fixatives, which are substances used to preserve artwork by creating a protective layer over the surface. Linseed oil, polymer, and poster colours are not typically applied with an atomizer.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A spatula can be improvised using</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feather</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charcoal.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A spatula, a tool used for mixing or applying paint, can be improvised using wood. Wood is a versatile material that can be shaped and sized to fit the needs of the artist. The other options, feather, clay, and charcoal, are not suitable materials for creating a spatula.</div>", "topic": "TOOLS, MATERIALS AND EQUIPMENT"}, {"id": "objective>Fine Art>2010>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pigments can be obtained locally from clay?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lemon yellow.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yellow ochre.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Blue.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Green.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Yellow ochre is a pigment that can be obtained locally from clay. It is a natural earth pigment containing hydrated iron oxide, which gives it a yellow color. Lemon yellow, blue, and green are not pigments that can be obtained from clay.</div>", "topic": "NIGERIAN CRAFTS"}, {"id": "objective>Fine Art>2010>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Architecture, an important feature of the built environment, is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Performing Art</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Visual Art</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Literary Art</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coptic Art.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Architecture is an example of Visual Art. Visual Art is a form of creative expression conveyed to the viewer through visual means, such as drawing, painting, sculpture, and architecture. Performing Art, Literary Art, and Coptic Art are not the correct categories for architecture.</div>", "topic": "CLASSIFICATION OF ART"}, {"id": "objective>Fine Art>2010>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ikogosi Warm Spring is described as a natural phenomenon because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is naturally warm in the dry season</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occurs naturally in the wet season</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occurs naturally</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is artificially kept warm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ikogosi Warm Spring is described as a natural phenomenon because it occurs naturally. A natural phenomenon is an observable event which is not man-made. Examples include sunrise, weather, fog, thunder, tornadoes; biological processes, decomposition, germination; physical processes, wave propagation, erosion; tidal flow, and natural disasters such as electromagnetic pulses, volcanic eruptions, and earthquakes.</div>", "topic": "TRADITIONAL NIGERIAN ART"}, {"id": "objective>Fine Art>2010>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A work of art is successful if the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">work is monumental</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colours are sharp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elements are well organized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surface is bright.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A work of art is successful if the elements are well organized. The organization of elements in a work of art creates a sense of balance and harmony. These elements include line, shape, form, color, space, texture, and value. When these elements are well organized, they create a pleasing or interesting visual effect and contribute to the overall success of the artwork.</div>", "topic": "ELEMENTS AND PRINCIPLES OF DESIGN"}, {"id": "objective>Fine Art>2010>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Captions used to enhance television announcements would be more understandable if produced <br/> as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">graphics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">painting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mosaics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">collage.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Captions used to enhance television announcements would be more understandable if produced as graphics. Graphics are visual images or designs on some surface, such as a wall, canvas, screen, paper, or stone to inform, illustrate, or entertain. In television announcements, graphics can include text, diagrams, pictures, and animations to convey information quickly and clearly.</div>", "topic": "ART TERMS"}];
